17	// triageDecisionEventKind is the event kind used to record the triage
18	// policy's chosen action after a non-APPROVE review verdict.
19	const triageDecisionEventKind = "triage-decision"
20	
21	// PostMergeReviewInput bundles the data RunPostMergeReview needs from its
22	// caller — historically the execute-bead loop body, now the per-attempt
23	// pipeline owned by try.Attempt (ddx-a921ff01 C3). The fields mirror what
24	// the inlined block read from the worker, the candidate bead, the report,
25	// and the loop runtime.
26	type PostMergeReviewInput struct {
27		Bead          bead.Bead
28		Report        ExecuteBeadReport
29		Reviewer      BeadReviewer
30		Store         ExecuteBeadLoopStore
31		ProjectRoot   string
32		Rcfg          config.ResolvedConfig
33		NoReview      bool
34		Log           io.Writer
35		Assignee      string
36		Now           func() time.Time
37		ReviewCostCap *escalation.CostCapTracker
38	}
39	
40	// PostMergeReviewOutput carries the review state machine's decision back to
41	// the caller. Report is the (possibly updated) ExecuteBeadReport; Approved
42	// reports whether the caller should treat this attempt as a success. When
43	// the review path encountered a non-fatal Store error the caller is expected
44	// to route StoreErr through its outcome-error handler
45	// (handleOutcomeStoreError on ExecuteBeadWorker), keyed by StoreErrOp.
46	type PostMergeReviewOutput struct {
47		Report     ExecuteBeadReport
48		Approved   bool
49		StoreErrOp string
50		StoreErr   error
51	}
52	
53	// RunPostMergeReview executes the post-merge review state machine for a
54	// successful bead attempt. When review is skipped (no reviewer or --no-review)
55	// the bead is closed and the function returns Approved=true. When review is
56	// active, the execute-loop asks the review coordinator to evaluate the
57	// close-eligible result before CloseWithEvidence runs; close only proceeds on
58	// unanimous evidence-backed APPROVE. REQUEST_CHANGES and BLOCK record their
59	// review events without reopening the bead.
60	//
61	// The review:skip label only skips when it carries a sibling
62	// review:skip-reason:* label; otherwise it is ignored. When review is not
63	// skipped, the review coordinator's verdict(s) or error drive the canonical
64	// event emissions (review / review-error / review-manual-required /
65	// review-malfunction), and on a non-APPROVE verdict the triage policy is
66	// still consulted without reopening the bead.
67	//
68	// Returns Approved=true on the APPROVE path and on the skip path; returns
69	// Approved=false on REQUEST_CHANGES, BLOCK, malformed APPROVE/BLOCK, or
70	// reviewer transport error. Store errors are surfaced via StoreErrOp +
71	// StoreErr so callers can keep the existing handleOutcomeStoreError pattern
72	// unchanged.
73	//
74	// This is the C3 (ddx-a921ff01) extraction of the 180-line review block
75	// previously inline in execute_bead_loop.go; the loop now sees a structured
76	// outcome and conflict-recovery / decomposition / no_changes paths remain
77	// in the loop body until subsequent C-series beads (C4, C5) move them too.
78	func RunPostMergeReview(ctx context.Context, in PostMergeReviewInput) PostMergeReviewOutput {
79		report := in.Report
80		out := PostMergeReviewOutput{Report: report, Approved: true}
81	
82		now := in.Now
83		if now == nil {
84			now = time.Now
85		}
86	
87		reviewSkipped := in.Reviewer == nil || in.NoReview
88		if !reviewSkipped && HasBeadLabel(in.Bead.Labels, "review:skip") {
89			reviewSkipped = HasBeadLabelPrefix(in.Bead.Labels, "review:skip-reason:")
90		}
91	
92		if reviewSkipped {
93			if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
94				out.StoreErrOp = "CloseWithEvidence"
95				out.StoreErr = err
96				return out
97			}
98			out.Report = report
99			return out
100		}
101	
102		implRouting := ImplementerRouting{
103			Harness:     report.Harness,
104			Provider:    report.Provider,
105			Model:       report.Model,
106			ActualPower: report.ActualPower,
107			Correlation: map[string]string{
108				"bead_id":    in.Bead.ID,
109				"attempt_id": report.AttemptID,
110				"session_id": report.SessionID,
111				"result_rev": report.ResultRev,
112			},
113		}
114		reviewGroup, reviewErr := runPreCloseReviewGroup(ctx, in.Reviewer, in.Bead.ID, report.ResultRev, implRouting)
115		reviewRes, reviewGroupErr := reducePreCloseReviewGroup(reviewGroup)
116		chargeReviewCost := func() bool {
117			budgetExceeded := false
118			if capTracker := in.ReviewCostCap; capTracker != nil && reviewGroup != nil {
119				deferred := false
120				for _, slot := range reviewGroup.Slots {
121					if slot.Result == nil {
122						continue
123					}
124					capTracker.Add(slot.Result.ReviewerHarness, slot.Result.CostUSD)
125					if detail, capped := capTracker.Tripped(); capped && !deferred {
126						_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
127							Kind:      "review-cost-deferred",
128							Summary:   "review-cost-deferred",
129							Body:      ReviewCostDeferredEventBody(report.ResultRev, slot.Result.CostUSD, capTracker.Spent(), capTracker.MaxUSD),
130							Actor:     in.Assignee,
131							Source:    "ddx agent execute-loop",
132							CreatedAt: now().UTC(),
133						})
134						if in.Log != nil {
135							_, _ = fmt.Fprintf(in.Log, "review cost cap deferred (%s %s): %s\n", in.Bead.ID, report.ResultRev, detail)
136						}
137						deferred = true
138						budgetExceeded = true
139					}
140				}
141			}
142			return budgetExceeded
143		}
144		if reviewGroupErr != nil {
145			reviewErr = reviewGroupErr
146		}
147		if reviewErr != nil {
148			class := ClassifyReviewError(reviewErr, reviewRes)
149			prior := CountPriorReviewErrors(in.Store, in.Bead.ID, report.ResultRev)
150			attemptCount := prior + 1
151			maxRetries := in.Rcfg.ReviewMaxRetries()
152			if maxRetries <= 0 {
153				maxRetries = DefaultReviewMaxRetries
154			}
155			errSummary := EventBodySummary{
156				InputBytes:  0,
157				OutputBytes: 0,
158			}
159			if reviewRes != nil {
160				errSummary = EventBodySummary{
161					Harness:     reviewRes.ReviewerHarness,
162					Model:       reviewRes.ReviewerModel,
163					InputBytes:  reviewRes.InputBytes,
164					OutputBytes: reviewRes.OutputBytes,
165					ElapsedMS:   reviewRes.DurationMS,
166				}
167			}
168			if attemptCount >= maxRetries {
169				body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
170				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
171					Kind:      "review-manual-required",
172					Summary:   class,
173					Body:      body,
174					Actor:     in.Assignee,
175					Source:    "ddx agent execute-loop",
176					CreatedAt: now().UTC(),
177				})
178				_ = in.Store.Update(in.Bead.ID, func(b *bead.Bead) {
179					if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
180						b.Labels = append(b.Labels, TriageNeedsHumanLabel)
181					}
182				})
183				parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
184				_ = in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, "review-manual-required", class)
185			} else {
186				body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
187				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
188					Kind:      "review-error",
189					Summary:   class,
190					Body:      body,
191					Actor:     in.Assignee,
192					Source:    "ddx agent execute-loop",
193					CreatedAt: now().UTC(),
194				})
195			}
196			if reviewRes != nil {
197				report.ReviewVerdict = string(reviewRes.Verdict)
198				report.ReviewRationale = reviewRes.Rationale
199			}
200			report.Status = ExecuteBeadStatusReviewMalfunction
201			report.Detail = "pre-close review: " + class
202			out.Report = report
203			out.Approved = false
204			chargeReviewCost()
205			return out
206		}
207	
208		report.ReviewVerdict = string(reviewRes.Verdict)
209		report.ReviewRationale = reviewRes.Rationale
210		artifactPath, artifactErr := PersistReviewerStream(in.ProjectRoot, in.Bead.ID, report.AttemptID, reviewRes.RawOutput)
211		if artifactErr != nil && in.Log != nil {
212			_, _ = fmt.Fprintf(in.Log, "reviewer stream artifact: %v\n", artifactErr)
213		}
214	
215		reviewSummary := EventBodySummary{
216			Harness:     reviewRes.ReviewerHarness,
217			Model:       reviewRes.ReviewerModel,
218			InputBytes:  reviewRes.InputBytes,
219			OutputBytes: reviewRes.OutputBytes,
220			ElapsedMS:   reviewRes.DurationMS,
221		}
222		reviewBudgetExceeded := chargeReviewCost()
223		switch reviewRes.Verdict {
224		case VerdictApprove:
225			// Approved: record the verdict event and then close. The close must
226			// land AFTER the review event so the gate sees the terminal verdict.
227			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
228				Kind:      "review",
229				Summary:   "APPROVE",
230				Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
231				Actor:     in.Assignee,
232				Source:    "ddx agent execute-loop",
233				CreatedAt: now().UTC(),
234			})
235			if reviewBudgetExceeded {
236				// Reviewer cost tripped the budget cap; leave bead open so the
237				// loop's BudgetStop can stop the drain before the next claim.
238				out.Report = report
239				out.Approved = false
240				return out
241			}
242			if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
243				out.Report = report
244				out.StoreErrOp = "CloseWithEvidence"
245				out.StoreErr = cerr
246				return out
247			}
248		case VerdictRequestChanges:
249			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
250				Kind:      "review",
251				Summary:   "REQUEST_CHANGES",
252				Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
253				Actor:     in.Assignee,
254				Source:    "ddx agent execute-loop",
255				CreatedAt: now().UTC(),
256			})
257			report.Status = ExecuteBeadStatusReviewRequestChanges
258			report.Detail = "pre-close review: REQUEST_CHANGES"
259			out.Approved = false
260		case VerdictBlock:
261			rationale := strings.TrimSpace(reviewRes.Rationale)
262			if rationale == "" {
263				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
264					Kind:      "review-malfunction",
265					Summary:   "BLOCK without rationale",
266					Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
267					Actor:     in.Assignee,
268					Source:    "ddx agent execute-loop",
269					CreatedAt: now().UTC(),
270				})
271				report.Status = ExecuteBeadStatusReviewMalfunction
272				report.Detail = "pre-close review: malformed BLOCK verdict (missing rationale)"
273				report.ReviewRationale = ""
274				out.Report = report
275				out.Approved = false
276				return out
277			}
278			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
279				Kind:      "review",
280				Summary:   "BLOCK",
281				Body:      AppendEventSummary(rationale, reviewSummary),
282				Actor:     in.Assignee,
283				Source:    "ddx agent execute-loop",
284				CreatedAt: now().UTC(),
285			})
286			if terminalClass := classifyTerminalReviewBlock(reviewRes); terminalClass != "" {
287				applyTerminalReviewBlock(in.Store, in.Bead.ID, in.Assignee, now().UTC(), terminalClass, report.ResultRev)
288				report.Status = ExecuteBeadStatusReviewTerminalBlock
289				report.Detail = "pre-close review: terminal " + terminalClass
290				out.Report = report
291				out.Approved = false
292				return out
293			}
294			report.Status = ExecuteBeadStatusReviewBlock
295			report.Detail = "pre-close review: BLOCK (flagged for human)"
296			out.Approved = false
297		}
298		if reviewRes.Verdict == VerdictBlock || reviewRes.Verdict == VerdictRequestChanges {
299			_ = applyReviewTriageDecision(in.Store, in.Bead.ID, in.Assignee, now().UTC(), report.Tier)
300		}
301	
302		out.Report = report
303		return out
304	}
