393	// applyReviewTriageDecision runs the triage policy after a BLOCK or
394	// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
395	// prior review events to compute the BLOCK count, biases the result toward
396	// re-attempt when the latest BLOCK was paired with a degraded reviewer
397	// (kind:review-pairing-degraded), then applies the chosen action by writing
398	// metadata, labels, and a kind:triage-decision event.
399	//
400	// Errors from the underlying store are best-effort: callers continue
401	// regardless so a triage-side failure cannot strand a bead in an
402	// inconsistent review state. This callout previously lived as a method on
403	// ExecuteBeadWorker; the C3
404	// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
405	// driven by RunPostMergeReview / try.Attempt.
406	func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
407		events, err := store.Events(beadID)
408		if err != nil {
409			return err
410		}
411	
412		var blockTimestamps []time.Time
413		var pairingDegraded []time.Time
414		for _, ev := range events {
415			switch {
416			case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
417				blockTimestamps = append(blockTimestamps, ev.CreatedAt)
418			case ev.Kind == ReviewPairingDegradedEventKind:
419				pairingDegraded = append(pairingDegraded, ev.CreatedAt)
420			}
421		}
422	
423		// History excludes the current attempt. The just-appended BLOCK (if any)
424		// is the last entry in blockTimestamps and must not be counted as prior
425		// history per triage.Decide()'s contract.
426		historyCount := len(blockTimestamps)
427		if historyCount > 0 {
428			historyCount--
429		}
430		history := make([]triage.FailureMode, 0, historyCount)
431		for i := 0; i < historyCount; i++ {
432			history = append(history, triage.FailureModeReviewBlock)
433		}
434	
435		policy := triage.DefaultPolicy()
436		action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)
437	
438		pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
439		if pairedDegraded && action == triage.ActionEscalateTier {
440			action = triage.ActionReAttemptWithContext
441		}
442	
443		return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
444	}
445	
446	// latestBlockPairedDegraded reports whether the most recent BLOCK event was
447	// paired with a review-pairing-degraded event from the same attempt window
448	// (between the previous BLOCK and this one).
449	func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
450		if len(blocks) == 0 || len(pairing) == 0 {
451			return false
452		}
453		latest := blocks[len(blocks)-1]
454		var prev time.Time
455		if len(blocks) >= 2 {
456			prev = blocks[len(blocks)-2]
457		}
458		for _, t := range pairing {
459			if t.After(prev) && !t.After(latest) {
460				return true
461			}
462		}
463		return false
464	}
465	
466	// applyTriageAction performs the side effects for a chosen Action: writes a
467	// tier-pin hint into bead.Extra (escalate_tier), appends a needs_human label
468	// (needs_human), and always records a kind:triage-decision event.
469	func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
470		body := map[string]any{
471			"action": string(action),
472			"mode":   string(triage.FailureModeReviewBlock),
473		}
474		if pairedDegraded {
475			body["pairing_degraded"] = true
476		}
477	
478		switch action {
479		case triage.ActionEscalateTier:
480			nextTier := nextEscalatedTier(currentTier)
481			body["tier_hint"] = string(nextTier)
482			_ = store.Update(beadID, func(b *bead.Bead) {
483				if b.Extra == nil {
484					b.Extra = make(map[string]any)
485				}
486				b.Extra[TriageTierHintKey] = string(nextTier)
487			})
488		case triage.ActionNeedsHuman:
489			_ = store.Update(beadID, func(b *bead.Bead) {
490				if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
491					b.Labels = append(b.Labels, TriageNeedsHumanLabel)
492				}
493			})
494		}
495	
496		bodyJSON, _ := json.Marshal(body)
497		return store.AppendEvent(beadID, bead.BeadEvent{
498			Kind:      triageDecisionEventKind,
499			Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
500			Body:      string(bodyJSON),
501			Actor:     actor,
502			Source:    "ddx agent execute-loop",
503			CreatedAt: now,
504		})
505	}
506	
507	// nextEscalatedTier returns the next tier above `current`. An unrecognised or
508	// empty current tier defaults to standard; smart is its own ceiling.
509	func nextEscalatedTier(current string) escalation.ModelTier {
510		switch escalation.ModelTier(current) {
511		case escalation.TierCheap:
512			return escalation.TierStandard
513		case escalation.TierStandard:
514			return escalation.TierSmart
515		case escalation.TierSmart:
516			return escalation.TierSmart
517		default:
518			return escalation.TierStandard
519		}
520	}
