package agent

import (
	"context"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestPreCloseReviewFixableGap_PreventsCloseAndSchedulesRepair verifies that a
// non-terminal BLOCK verdict is classified as review_fixable_gap:
//   - CloseWithEvidence is not called (bead remains open and not closed)
//   - A review-fixable-gap event is recorded with the correct result_rev body
//   - PostMergeReviewOutput.RepairContext is non-nil with the expected fields
//   - Status is ExecuteBeadStatusReviewFixableGap
//
// It also covers the one-cycle scheduling limit (AC4): a second call to
// RunPostMergeReview for the same result_rev must not schedule another repair
// cycle; it must fall through to the regular BLOCK path (status = review_block,
// RepairContext = nil).
func TestPreCloseReviewFixableGap_PreventsCloseAndSchedulesRepair(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)

	const resultRev = "fixable01"
	const blockRationale = "error handling missing in pkg/foo.go:42"
	const implPower = 70

	reviewer := beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       blockRationale,
			RawOutput:       "BLOCK: " + blockRationale,
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
			ResultRev:       resultRev,
		}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	report := ExecuteBeadReport{
		BeadID:      first.ID,
		Status:      ExecuteBeadStatusSuccess,
		SessionID:   "sess-fixable",
		ResultRev:   resultRev,
		BaseRev:     "fixable00",
		ActualPower: implPower,
	}

	// First review: must yield review_fixable_gap with a repair context.
	out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
		Bead:     *first,
		Report:   report,
		Reviewer: reviewer,
		Store:    store,
		Rcfg:     rcfg,
		Assignee: "worker",
	})

	assert.False(t, out.Approved, "review_fixable_gap must not be approved")
	assert.Equal(t, ExecuteBeadStatusReviewFixableGap, out.Report.Status)
	assert.Nil(t, out.StoreErr)

	// RepairContext must be populated.
	require.NotNil(t, out.RepairContext, "review_fixable_gap must set RepairContext")
	assert.Equal(t, resultRev, out.RepairContext.ResultRev)
	assert.Equal(t, blockRationale, out.RepairContext.ReviewRationale)
	assert.Equal(t, implPower, out.RepairContext.ImplementerActualPower)

	// review-fixable-gap event must be recorded with result_rev in the body.
	events, err := store.Events(first.ID)
	require.NoError(t, err)
	var fixableEv *bead.BeadEvent
	for i := range events {
		if events[i].Kind == ReviewFixableGapEventKind {
			fixableEv = &events[i]
		}
	}
	require.NotNil(t, fixableEv, "review-fixable-gap event must be recorded")
	assert.Equal(t, "review_fixable_gap", fixableEv.Summary)
	assert.Contains(t, fixableEv.Body, "result_rev="+resultRev)

	// Bead must remain open.
	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.NotEqual(t, bead.StatusClosed, got.Status, "bead must not be closed on review_fixable_gap")
}

// TestRetryPolicy_ReviewFixableGapStopsAfterOneRepairCycle verifies that a
// second BLOCK verdict on the same result_rev does NOT schedule a second
// repair cycle. Once a review-fixable-gap event exists for a result_rev, the
// repair path is bypassed and RunPostMergeReview returns status=review_block
// with RepairContext=nil so the normal BLOCK triage fires instead.
func TestRetryPolicy_ReviewFixableGapStopsAfterOneRepairCycle(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)

	const resultRev = "fixable02"
	const blockRationale = "still missing error handling"

	reviewer := beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		return &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       blockRationale,
			RawOutput:       "BLOCK: " + blockRationale,
			ReviewerHarness: "claude",
			ReviewerModel:   "claude-opus-4-6",
			ResultRev:       resultRev,
		}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	report := ExecuteBeadReport{
		BeadID:      first.ID,
		Status:      ExecuteBeadStatusSuccess,
		SessionID:   "sess-onecycle",
		ResultRev:   resultRev,
		BaseRev:     "fixable01",
		ActualPower: 70,
	}

	input := PostMergeReviewInput{
		Bead:     *first,
		Report:   report,
		Reviewer: reviewer,
		Store:    store,
		Rcfg:     rcfg,
		Assignee: "worker",
	}

	// First call: schedules repair cycle.
	out1 := RunPostMergeReview(context.Background(), input)
	require.NotNil(t, out1.RepairContext, "first review must schedule a repair cycle")
	assert.Equal(t, ExecuteBeadStatusReviewFixableGap, out1.Report.Status)

	// Second call for the same result_rev: must NOT schedule another repair.
	out2 := RunPostMergeReview(context.Background(), input)
	assert.Nil(t, out2.RepairContext, "second review on same result_rev must not schedule another repair")
	assert.Equal(t, ExecuteBeadStatusReviewBlock, out2.Report.Status,
		"second BLOCK on same result_rev must fall through to regular review_block")
	assert.False(t, out2.Approved)
}

package cmd

import (
	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// reviewRepairAttemptArgs bundles the arguments that must be forwarded to
// singleTierAttempt for a review_fixable_gap repair cycle. MinPower is raised
// above the implementer's actual power; all other routing pins are forwarded
// unchanged from the original attempt.
type reviewRepairAttemptArgs struct {
	MinPower int
	Harness  string
	Model    string
	Provider string
	Profile  string
	// MaxPower is the operator's explicit cap, preserved as-is (0 = unset).
	MaxPower int
}

// reviewFixableGapRepairMinPower returns the MinPower floor for a repair
// attempt that follows a review_fixable_gap verdict. It advances the
// escalation ladder from the implementer's actual power to the next higher
// floor so the repair runs on a stronger model than the original implementer.
//
// If the ladder has no higher floor (exhausted), it returns implActualPower
// so the repair attempt at least carries the review rationale as additional
// context even if the same power tier is used.
func reviewFixableGapRepairMinPower(repairCtx *agent.RepairContextFromReviewGroup, ladder escalationFloorFinder) int {
	if repairCtx == nil {
		return 0
	}
	next, err := nextEscalationFloor(ladder, repairCtx.ImplementerActualPower)
	if err != nil {
		return repairCtx.ImplementerActualPower
	}
	return next
}

// reviewFixableGapRepairArgs computes the singleTierAttempt arguments for a
// repair attempt. MinPower is raised above the implementer's actual power
// using the escalation ladder. All explicit harness/model/provider/profile
// pins are forwarded unchanged. MaxPower is preserved from the operator's
// original setting (0 means unset — the repair must not add a cap the
// operator did not request).
func reviewFixableGapRepairArgs(
	repairCtx *agent.RepairContextFromReviewGroup,
	harness, model, provider, profile string,
	maxPower int,
	ladder escalationFloorFinder,
) reviewRepairAttemptArgs {
	return reviewRepairAttemptArgs{
		MinPower: reviewFixableGapRepairMinPower(repairCtx, ladder),
		Harness:  harness,
		Model:    model,
		Provider: provider,
		Profile:  profile,
		MaxPower: maxPower,
	}
}

package cmd

import (
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	tierescalation "github.com/DocumentDrivenDX/ddx/internal/agent/escalation"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestRetryPolicy_ReviewFixableGapRaisesMinPowerAndPreservesPins proves that
// reviewFixableGapRepairArgs:
//   - Raises MinPower strictly above the implementer's actual power by
//     consulting the escalation ladder.
//   - Preserves explicit harness/model/provider/profile pins unchanged.
//   - Leaves MaxPower unset (0) when the operator did not set it, so the
//     repair attempt does not acquire a power cap the operator never requested.
func TestRetryPolicy_ReviewFixableGapRaisesMinPowerAndPreservesPins(t *testing.T) {
	ladder := &ladderSpy{responses: []ladderResponse{{next: 90}}}

	repairCtx := &agent.RepairContextFromReviewGroup{
		ImplementerActualPower: 70,
		ResultRev:              "abc123",
		ReviewRationale:        "error handling missing",
	}

	args := reviewFixableGapRepairArgs(
		repairCtx,
		"claude",        // harness
		"claude-opus-4-6", // model
		"anthropic",    // provider
		"",             // profile (unset)
		0,              // maxPower (operator did not set)
		ladder,
	)

	assert.Greater(t, args.MinPower, repairCtx.ImplementerActualPower,
		"repair MinPower must exceed implementer actual power")
	assert.Equal(t, 90, args.MinPower, "repair MinPower must match ladder's next floor")
	assert.Equal(t, "claude", args.Harness, "harness pin must be preserved")
	assert.Equal(t, "claude-opus-4-6", args.Model, "model pin must be preserved")
	assert.Equal(t, "anthropic", args.Provider, "provider pin must be preserved")
	assert.Equal(t, "", args.Profile, "profile pin must be preserved")
	assert.Equal(t, 0, args.MaxPower,
		"MaxPower must remain unset when the operator did not set it")

	assert.Equal(t, []int{70}, ladder.CalledWith(),
		"ladder must be consulted with implementer actual power")
}

// TestRetryPolicy_ReviewFixableGapRaisesMinPower_LadderExhausted verifies
// that when the escalation ladder has no higher floor, reviewFixableGapRepairMinPower
// returns the implementer's actual power rather than zero so the repair attempt
// still carries the review rationale as context.
func TestRetryPolicy_ReviewFixableGapRaisesMinPower_LadderExhausted(t *testing.T) {
	ladder := &ladderSpy{responses: []ladderResponse{
		{err: tierescalation.ErrLadderExhausted},
	}}

	repairCtx := &agent.RepairContextFromReviewGroup{
		ImplementerActualPower: 90,
	}

	minPower := reviewFixableGapRepairMinPower(repairCtx, ladder)
	require.Equal(t, 90, minPower,
		"exhausted ladder must fall back to implementer actual power")
}

